problems.optimal_solution:
SELECT p.firstName, p.lastName, a.city, a.state
FROM Person p
LEFT JOIN Address a ON p.personId = a.personId;

SELECT name FROM SalesPerson
WHERE sales_id NOT IN (
  SELECT DISTINCT o.sales_id FROM Orders o
  JOIN Company c ON o.com_id = c.com_id
  WHERE c.name = 'RED'
);

SELECT w.name AS warehouse_name, SUM(w.units * p.Width * p.Length * p.Height) AS volume
FROM Warehouse w JOIN Products p ON w.product_id = p.product_id
GROUP BY w.name;

SELECT u.name, SUM(t.amount) AS balance
FROM Users u JOIN Transactions t ON u.account = t.account
GROUP BY u.account HAVING balance > 10000;

SELECT e.employee_id, t.team_size FROM Employee e
JOIN (SELECT team_id, COUNT(*) AS team_size FROM Employee GROUP BY team_id) t
ON e.team_id = t.team_id;

SELECT DISTINCT c.title FROM TVProgram t
JOIN Content c ON t.content_id = c.content_id
WHERE c.Kids_content = 'Y' AND YEAR(t.program_date) = 2020 AND MONTH(t.program_date) = 10;

SELECT DISTINCT c1.seat_id FROM Cinema c1
JOIN Cinema c2 ON ABS(c1.seat_id - c2.seat_id) = 1
WHERE c1.free = 1 AND c2.free = 1 ORDER BY c1.seat_id;

SELECT product_id, 'store1' AS store, store1 AS price FROM Products WHERE store1 IS NOT NULL
UNION ALL SELECT product_id, 'store2', store2 FROM Products WHERE store2 IS NOT NULL
UNION ALL SELECT product_id, 'store3', store3 FROM Products WHERE store3 IS NOT NULL;

SELECT LEAST(from_id, to_id) AS person1, GREATEST(from_id, to_id) AS person2,
  COUNT(*) AS call_count, SUM(duration) AS total_duration
FROM Calls GROUP BY person1, person2;

SELECT player_id, event_date,
  SUM(games_played) OVER (PARTITION BY player_id ORDER BY event_date) AS games_played_so_far
FROM Activity;

SELECT d.name AS Department, e.name AS Employee, e.salary
FROM Employee e JOIN Department d ON e.departmentId = d.id
WHERE (e.departmentId, e.salary) IN (SELECT departmentId, MAX(salary) FROM Employee GROUP BY departmentId);

SELECT p.player_id, p.player_name, COUNT(*) AS grand_slams_count
FROM Players p
JOIN (
  SELECT wimbledon AS id FROM Championships UNION ALL SELECT Fr_open UNION ALL SELECT US_open UNION ALL SELECT Au_open
) t ON p.player_id = t.id GROUP BY p.player_id;

SELECT transaction_id FROM Transactions
WHERE (DATE(day), amount) IN (SELECT DATE(day), MAX(amount) FROM Transactions GROUP BY DATE(day))
ORDER BY transaction_id;

SELECT e.left_operand, e.operator, e.right_operand,
  CASE WHEN e.operator='>' AND lv.value>rv.value THEN 'true' WHEN e.operator='<' AND lv.value<rv.value THEN 'true' WHEN e.operator='=' AND lv.value=rv.value THEN 'true' ELSE 'false' END AS value
FROM Expressions e JOIN Variables lv ON e.left_operand=lv.name JOIN Variables rv ON e.right_operand=rv.name;

WITH cte AS (
  SELECT customer_id, product_id, RANK() OVER (PARTITION BY customer_id ORDER BY COUNT(*) DESC) AS rk
  FROM Orders GROUP BY customer_id, product_id
)
SELECT c.customer_id, c.product_id, p.product_name
FROM cte c JOIN Products p ON c.product_id = p.product_id WHERE c.rk = 1;

WITH t AS (
  SELECT user_id, visit_date,
    LEAD(visit_date, 1, '2021-01-01') OVER (PARTITION BY user_id ORDER BY visit_date) AS next_visit
  FROM UserVisits
)
SELECT user_id, MAX(DATEDIFF(next_visit, visit_date)) AS biggest_window FROM t GROUP BY user_id;

SELECT p.project_id, p.employee_id FROM Project p JOIN Employee e ON p.employee_id = e.employee_id
WHERE (p.project_id, e.experience_years) IN (
  SELECT p2.project_id, MAX(e2.experience_years) FROM Project p2 JOIN Employee e2 ON p2.employee_id = e2.employee_id GROUP BY p2.project_id
);

WITH RECURSIVE cte AS (
  SELECT employee_id FROM Employees WHERE manager_id = 1 AND employee_id != 1
  UNION ALL
  SELECT e.employee_id FROM Employees e JOIN cte ON e.manager_id = cte.employee_id WHERE e.employee_id != 1
)
SELECT employee_id FROM cte;

WITH exam_stats AS (SELECT exam_id, MAX(score) AS max_s, MIN(score) AS min_s FROM Exam GROUP BY exam_id)
SELECT DISTINCT s.student_id, s.student_name FROM Student s JOIN Exam e ON s.student_id = e.student_id
WHERE s.student_id NOT IN (
  SELECT e2.student_id FROM Exam e2 JOIN exam_stats es ON e2.exam_id = es.exam_id
  WHERE e2.score = es.max_s OR e2.score = es.min_s
) ORDER BY s.student_id;

WITH all_dates AS (
  SELECT fail_date AS dt, 'failed' AS state FROM Failed WHERE YEAR(fail_date) = 2019
  UNION ALL SELECT success_date, 'succeeded' FROM Succeeded WHERE YEAR(success_date) = 2019
),
grp AS (
  SELECT dt, state, SUBDATE(dt, ROW_NUMBER() OVER (PARTITION BY state ORDER BY dt)) AS grp_key FROM all_dates
)
SELECT state AS period_state, MIN(dt) AS start_date, MAX(dt) AS end_date
FROM grp GROUP BY state, grp_key ORDER BY start_date;
